import React, { useEffect, useState } from "react";
import axios from "axios";

const Positions = () => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchPositions = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_API_URL || "http://localhost:3002"}/allPositions`
        );
        setPositions(res.data || []);
      } catch (err) {
        console.error("Failed to fetch positions:", err);
        setError("Failed to load positions.");
      } finally {
        setLoading(false);
      }
    };

    fetchPositions();
  }, []);

  const formatCurrency = (value) =>
    value.toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading positions...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Positions ({positions.length})</h3>

      <div className="order-tables">
        <table>
          <thead>
            <tr>
              <th>Product</th>
              <th>Stock</th>
              <th>Qty</th>
              <th>Avg</th>
              <th>LTP</th>
              <th>P&L</th>
              <th>Net</th>
              <th>Day</th>
            </tr>
          </thead>

          <tbody>
            {positions.map((stock) => {
              const pnl =
                (stock.price || 0) * (stock.qty || 0) -
                (stock.avg || 0) * (stock.qty || 0);

              const pnlClass = pnl >= 0 ? "profit" : "loss";
              const dayClass = stock.day?.includes("-")
                ? "loss"
                : "profit";

              return (
                <tr key={stock.name}>
                  <td>{stock.product}</td>
                  <td>{stock.name}</td>
                  <td>{stock.qty}</td>
                  <td>₹{formatCurrency(stock.avg)}</td>
                  <td>₹{formatCurrency(stock.price)}</td>
                  <td className={pnlClass}>
                    ₹{formatCurrency(pnl)}
                  </td>
                  <td className={pnlClass}>{stock.net}</td>
                  <td className={dayClass}>{stock.day}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </>
  );
};

export default Positions;
